import { ChatFlow, CustomTool } from 'flowise';

const detectAuthlessTools = (chatflow: ChatFlow) => {
  const issues: string[] = [];

  chatflow.data.nodes.forEach(node => {
    if (node.type === 'customTool' && node.data) {
      const tool = node.data as CustomTool;
      // Check if tool function references user/session validation
      const hasAuthCheck = tool.code.includes('user') || 
                          tool.code.includes('session') ||
                          tool.code.includes('auth') ||
                          tool.code.includes('permissions');

      if (!hasAuthCheck && (tool.code.includes('db') || tool.code.includes('sql') || tool.code.includes('api'))) {
        issues.push(`Tool ${node.data.name} lacks auth checks but accesses sensitive resources`);
      }
    }
  });

  return issues;
};

const traceAgentContextFlow = (chatflow: ChatFlow) => {
  const contextLosses: string[] = [];
  let currentContext: string[] = [];

  chatflow.data.nodes.forEach((node, index) => {
    if (node.type === 'agent') {
      const hasContextInput = node.data.inputs?.some(input => 
        input.name === 'userContext' || input.name === 'session'
      );

      if (!hasContextInput && currentContext.length > 0) {
        contextLosses.push(`Agent ${node.data.name} loses user context from previous nodes`);
      }

      // Assume agent preserves context unless explicitly dropped
      if (node.data.tools?.some(tool => tool.requiresAdmin)) {
        currentContext.push('adminPrivileges');
      }
    }
  });

  return contextLosses;
};

const auditVectorStoreAuth = (chatflow: ChatFlow) => {
  const violations: string[] = [];

  chatflow.data.nodes.forEach(node => {
    if (node.type === 'vectorStoreRetriever') {
      const retrieverConfig = node.data;

      // Check for tenant/user filtering in query
      const hasUserFilter = retrieverConfig.query?.includes('userId') ||
                           retrieverConfig.query?.includes('tenantId') ||
                           retrieverConfig.filter?.includes('permissions');

      if (!hasUserFilter) {
        violations.push(`Vector store ${node.data.name} lacks user-specific filtering`);
      }
    }
  });

  return violations;
};

