import { Vex } from '@vex_dev/sdk';
import { ChatFlowRequest, ChatFlowResponse } from 'flowise';

const vex = new Vex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!
});

// Flowise Global Callback Handler
export const flowiseAuthGuard = async (
  req: ChatFlowRequest,
  res: ChatFlowResponse
): Promise<ChatFlowResponse> => {
  // 1. Trace auth context through entire flow
  const authTrace = await vex.trace({
    type: 'flowise.auth',
    chatflowId: req.body.chatflowid,
    userContext: req.body.userContext,
    override: {
      policy: 'agent-auth-validation',
      threshold: 'critical'
    }
  });

  if (authTrace.violations.length > 0) {
    return {
      text: 'Access denied: Missing permissions',
      sourceDocuments: [],
      flagged: authTrace.violations
    };
  }

  // 2. Execute with Vex monitoring
  const monitoredRes = await vex.monitor(
    () => req.originalResponse,
    {
      spans: ['tool_calls', 'vector_retrieval', 'agent_handoffs'],
      assertions: [
        'userContext.present',
        'permissions.checked',
        'no_privilege_escalation'
      ]
    }
  );

  return monitoredRes;
};

// Install: npm install flowise @vex_dev/sdk
